using BenchmarkDotNet.Configs;
using BenchmarkDotNet.Jobs;
using BenchmarkDotNet.Running;
using TextAnalysis;

BenchmarkRunner.Run<TextAnalyzerBenchmarks>(
    DefaultConfig.Instance
        .AddJob(Job.Default.WithId(".NET 9").WithRuntime(BenchmarkDotNet.Environments.CoreRuntime.Core90))
        .AddJob(Job.Default.WithId(".NET 10").WithRuntime(BenchmarkDotNet.Environments.CoreRuntime.Core100))
);

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    private static string BuildSampleText()
    {
        var words = new[] {
            "the", "quick", "brown", "fox", "jumps", "over", "the", "lazy", "dog",
            "performance", "benchmarking", "is", "essential", "for", "understanding",
            "how", "code", "behaves", "under", "different", "runtime", "versions",
            "and", "configurations", "that", "may", "affect", "throughput", "or", "latency"
        };
        // ~3000 words
        return string.Join(' ', Enumerable.Range(0, 100).SelectMany(_ => words));
    }

    [GlobalSetup]
    public void Setup() => _analyzer = new TextAnalyzer(BuildSampleText());

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

